import{e as n}from"./app.3c7232da.js";import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";const s={},p=n(`<h2 id="\u524D\u8A00" tabindex="-1"><a class="header-anchor" href="#\u524D\u8A00" aria-hidden="true">#</a> \u524D\u8A00</h2><p>\u4E3A\u4E86\u89E3\u51B3\u6211\u4EEC\u5F00\u53D1\u8005\u5728 J2EE \u5F00\u53D1\u65F6\u6240\u9047\u5230\u7684\u4F17\u591A\u95EE\u9898\uFF0CRob Johnson \u7B49\u4EBA\u53D1\u8D77\u4E86 Spring \u6846\u67B6\u9879\u76EE\u3002Spring \u662F\u4E00\u4E2A\u5F00\u6E90\u7684 J2EE \u5E94\u7528\u7A0B\u5E8F\u6846\u67B6\uFF0C\u662F\u9488\u5BF9 Bean \u7684\u751F\u547D\u5468\u671F\u8FDB\u884C\u7BA1\u7406\u7684\u8F7B\u91CF\u7EA7\u5BB9\u5668\u3002\u5B83\u65E2\u53EF\u4EE5\u5355\u72EC\u7528\u4E8E\u6784\u5EFA\u7A0B\u5E8F\uFF0C\u4E5F\u80FD\u548C\u5F53\u524D\u4F17\u591A\u7684 Web \u6846\u67B6\u8FDB\u884C\u7EC4\u5408\u4F7F\u7528\uFF0C\u80FD\u591F\u5341\u5206\u65B9\u4FBF\u7684\u964D\u4F4E\u5F53\u524D\u4F01\u4E1A\u5E94\u7528\u5F00\u53D1\u7684\u590D\u6742\u6027\u3002\u65E2\u7136 Spring \u5982\u6B64\u5F3A\u5927\uFF0C\u90A3\u6211\u4EEC\u4ECA\u5929\u5C31\u6765\u63A2\u7A76\u4E00\u4E0B Spring \u7684\u5185\u5BB9\u3002</p><h2 id="spring-\u6982\u89C8" tabindex="-1"><a class="header-anchor" href="#spring-\u6982\u89C8" aria-hidden="true">#</a> Spring \u6982\u89C8</h2><p>Spring \u5176\u5B9E\u662F\u4E00\u4E2A\u5F88\u5927\u7684\u8303\u56F4\u6982\u79F0\uFF0C\u5305\u542B\u7740\u8BB8\u591A\u5206\u652F\uFF0C\u5728\u6B63\u5F0F\u4E86\u89E3 Spring \u4E4B\u524D\uFF0C\u6211\u4EEC\u5148\u6765\u770B\u770B Spring \u5BB6\u65CF\u4E2D\u7684\u4E3B\u8981\u5206\u652F\u3002</p><h3 id="spring-framewok" tabindex="-1"><a class="header-anchor" href="#spring-framewok" aria-hidden="true">#</a> Spring FrameWok</h3><p>Spring \u9886\u57DF\u4E2D\u5176\u4ED6\u4E00\u5207\u7684\u57FA\u7840\uFF0C\u63D0\u4F9B\u4E86 <strong>\u6838\u5FC3\u5BB9\u5668\u548C\u4F9D\u8D56\u6CE8\u5165\u6846\u67B6</strong>\uFF0C\u8FD8\u63D0\u4F9B\u4E86\u4E00\u4E9B\u57FA\u672C\u6570\u636E\u6301\u4E45\u6027\u652F\u6301\uFF0C\u7279\u522B\u662F\u57FA\u4E8E\u6A21\u677F\u7684 JDBC \u6587\u4EF6\u3002</p><h3 id="spring-boot" tabindex="-1"><a class="header-anchor" href="#spring-boot" aria-hidden="true">#</a> Spring Boot</h3><p>Spring Boot \u4E0D\u4EC5\u63D0\u4F9B\u4E86 <strong>\u542F\u52A8\u4F9D\u8D56\u548C\u81EA\u52A8\u914D\u7F6E</strong>\uFF0C\u8FD8\u63D0\u4F9B\u4E86\u5982\u4E0B\u7684\u5176\u4ED6\u7279\u6027\uFF1A</p><ol><li><p>Actuator \u63D0\u4F9B\u4E86\u5BF9\u5E94\u7528\u7A0B\u5E8F\u5185\u90E8\u5DE5\u4F5C\u65B9\u5F0F\u7684\u8FD0\u884C\u65F6\u76D1\u63A7\uFF0C\u5305\u62EC\u7AEF\u70B9\u3001\u7EBF\u7A0B dump \u4FE1\u606F\u3001\u5E94\u7528\u7A0B\u5E8F\u5065\u5EB7\u72B6\u51B5\u548C\u5E94\u7528\u7A0B\u5E8F\u53EF\u7528\u7684\u73AF\u5883\u5C5E\u6027\u3002</p></li><li><p>\u7075\u6D3B\u7684\u73AF\u5883\u5C5E\u6027\u89C4\u8303\u3002</p></li><li><p>\u6838\u5FC3\u6846\u67B6\u7684\u8F85\u52A9\u6D4B\u8BD5\u4E4B\u5916\u7684\u989D\u5916\u6D4B\u8BD5\u652F\u6301\u3002</p></li></ol><h3 id="spring-data" tabindex="-1"><a class="header-anchor" href="#spring-data" aria-hidden="true">#</a> Spring Data</h3><p>\u5C06\u5E94\u7528\u7A0B\u5E8F\u7684\u6570\u636E\u5B58\u50A8\u5E93\u62BD\u8C61\u4E3A\u7B80\u5355\u7684 Java \u63A5\u53E3\uFF0C\u540C\u65F6\u5F53\u5B9A\u4E49\u65B9\u6CD5\u7528\u4E8E\u9A71\u52A8\u6570\u636E\u8FDB\u884C\u5B58\u50A8\u548C\u68C0\u7D22\u7684\u95EE\u9898\u65F6\uFF0C\u5BF9\u65B9\u6CD5\u4F7F\u7528\u4E86\u547D\u540D\u7EA6\u5B9A\u3002\u6B64\u5916\u8FD8\u80FD\u5904\u7406\u51E0\u79CD\u4E0D\u540C\u7C7B\u578B\u7684\u6570\u636E\u5E93\uFF0C\u5305\u62EC\u5305\u62EC\u5173\u7CFB\u578B\uFF08JPA\uFF09\u3001\u6587\u6863\u578B\uFF08Mongo\uFF09\u3001\u56FE\u578B\uFF08Neo4j\uFF09\u7B49\u3002</p><h3 id="spring-security" tabindex="-1"><a class="header-anchor" href="#spring-security" aria-hidden="true">#</a> Spring Security</h3><p>Spring Security \u89E3\u51B3\u4E86\u5E7F\u6CDB\u7684\u5E94\u7528\u7A0B\u5E8F\u5B89\u5168\u6027\u9700\u6C42\uFF0C\u5305\u62EC\u8EAB\u4EFD\u9A8C\u8BC1\u3001\u6388\u6743\u548C API \u5B89\u5168\u6027\u7B49\u4E00\u7CFB\u5217\u5DE5\u4F5C\u3002</p><h3 id="spring-integration-\u548C-spring-batch" tabindex="-1"><a class="header-anchor" href="#spring-integration-\u548C-spring-batch" aria-hidden="true">#</a> Spring Integration \u548C Spring Batch</h3><p>Spring Integration \u89E3\u51B3\u4E86\u5B9E\u65F6\u96C6\u6210\uFF0C\u5373\u6570\u636E\u5728\u53EF\u7528\u65F6\u8FDB\u884C\u5904\u7406\u3002\u76F8\u53CD\uFF0CSpring Batch \u89E3\u51B3\u4E86\u6279\u91CF\u96C6\u6210\u7684\u95EE\u9898\uFF0C\u5141\u8BB8\u5728\u4E00\u6BB5\u65F6\u95F4\u5185\u6536\u96C6\u6570\u636E\uFF0C\u76F4\u5230\u67D0\u4E2A\u89E6\u53D1\u5668\uFF08\u53EF\u80FD\u662F\u4E00\u4E2A\u65F6\u95F4\u89E6\u53D1\u5668\uFF09\u53D1\u51FA\u4FE1\u53F7\uFF0C\u8868\u793A\u8BE5\u5904\u7406\u4E00\u6279\u6570\u636E\u3002</p><h3 id="spring-cloud" tabindex="-1"><a class="header-anchor" href="#spring-cloud" aria-hidden="true">#</a> Spring Cloud</h3><p>Spring Cloud \u662F\u4E00\u7EC4\u7528 Spring \u5F00\u53D1\u4E91\u672C\u5730\u5E94\u7528\u7A0B\u5E8F\u7684\u9879\u76EE\u3002</p><p>Spring \u662F\u4E3A\u4E86\u51CF\u5C11 EJB \u7684\u590D\u6742\u6027\u800C\u521B\u5EFA\u7684\u4E00\u5957\u89E3\u51B3\u65B9\u6848\uFF0C\u800C EJB \u8FC7\u4E8E\u81C3\u80BF\uFF0C\u4F7F\u7528 Spring \u80FD\u591F\u8BA9 Java Bean \u4E4B\u95F4\u8FDB\u884C\u6709\u6548\u7684\u89E3\u8026\u3002\u800C\u4E14 Spring \u4E0D\u4EC5\u4EC5\u5C40\u9650\u4E8E\u670D\u52A1\u7AEF\u7684\u5F00\u53D1\uFF0C\u5728\u6D4B\u8BD5\u6027\u548C\u677E\u8026\u5408\u65B9\u9762\u5747\u6709\u8F83\u597D\u8868\u73B0\u3002</p><h2 id="\u4EC0\u4E48\u662F-spring" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F-spring" aria-hidden="true">#</a> \u4EC0\u4E48\u662F Spring</h2><h3 id="spring-\u7B80\u4ECB" tabindex="-1"><a class="header-anchor" href="#spring-\u7B80\u4ECB" aria-hidden="true">#</a> Spring \u7B80\u4ECB</h3><p>\u6211\u4EEC\u65E5\u5E38\u6240\u8BF4\u7684 Spring\uFF0C\u5B9E\u9645\u4E0A\u6307\u7684\u662F Spring Framework\uFF0C\u5C5E\u4E8E Spring \u5BB6\u65CF\u7684\u4E00\u4E2A\u5206\u652F\u3002</p><p>Spring \u7684\u6838\u5FC3\u662F\u4E00\u4E2A <strong>\u5BB9\u5668</strong>\uFF0C\u5E38\u79F0\u4E3A <strong>Spring \u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587</strong>\uFF0C\u7528\u4E8E\u521B\u5EFA\u548C\u7BA1\u7406\u5E94\u7528\u7A0B\u5E8F\u7EC4\u4EF6\u3002\u7EC4\u4EF6\uFF08\u6216 Bean\uFF09\u5728 Spring \u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u4E2D\u8FDE\u63A5\u5728\u4E00\u8D77\u4E92\u76F8\u6784\u6210\u4E00\u4E2A\u5B8C\u6574\u7684\u5E94\u7528\u7A0B\u5E8F\u3002</p><p>\u90A3\u4E48\u662F\u5982\u4F55\u5C06\u5404\u79CD Bean \u8FDE\u63A5\u5728\u4E00\u8D77\u5462\uFF1F\u8FD9\u5C31\u662F Spring \u4E2D\u6700\u91CD\u8981\u7684\u7279\u6027\u4E4B\u4E00\uFF1A<strong>\u4F9D\u8D56\u6CE8\u5165\uFF08DI\uFF09</strong>\u3002</p><p><strong>\u4F9D\u8D56\u6CE8\u5165\uFF08DI\uFF09</strong>\uFF1A\u901A\u8FC7\u4F9D\u8D56\u6CE8\u5165\u7684\u5E94\u7528\u7A0B\u5E8F <strong>\u4E0D\u662F</strong> \u7531\u7EC4\u4EF6\u81EA\u8EAB\u521B\u5EFA\u548C\u7EF4\u62A4\u5176\u6240\u4F9D\u8D56\u7684\u5176\u4ED6 Bean \u7684\u751F\u547D\u5468\u671F\uFF0C<strong>\u800C\u662F\u4F9D\u8D56\u4E8E\u5355\u72EC\u7684\u5B9E\u4F53\uFF08\u5BB9\u5668\uFF09\u6765\u521B\u5EFA\u548C\u7EF4\u62A4\u6240\u6709\u7EC4\u4EF6\uFF0C\u5E76\u5C06\u8FD9\u4E9B\u7EC4\u4EF6\u6CE8\u5165\u9700\u8981\u4ED6\u4EEC\u7684 Bean\uFF0C\u901A\u5E38\u662F\u901A\u8FC7\u6784\u9020\u51FD\u6570\u6216\u5C5E\u6027\u8BBF\u95EE\u5668\u65B9\u6CD5\u6765\u5B8C\u6210</strong>\u3002</p><h3 id="spring-\u7684\u7279\u70B9" tabindex="-1"><a class="header-anchor" href="#spring-\u7684\u7279\u70B9" aria-hidden="true">#</a> Spring \u7684\u7279\u70B9</h3><ul><li><p>\u65B9\u4FBF\u89E3\u8026\uFF0C\u7B80\u5316\u5F00\u53D1\u8FC7\u7A0B\uFF1B</p></li><li><p>\u652F\u6301\u9762\u5411\u5207\u9762\u7F16\u7A0B\uFF08Aop\uFF09\uFF0C\u65B9\u4FBF\u6211\u4EEC\u4E0D\u7528\u4FEE\u6539\u6E90\u7801\u5C31\u80FD\u5BF9\u529F\u80FD\u8FDB\u884C\u589E\u5F3A\uFF1B</p></li><li><p>\u6574\u5408\u652F\u6301 Junit\uFF0C\u65B9\u4FBF\u7A0B\u5E8F\u7684\u6D4B\u8BD5\uFF1B</p></li><li><p>\u65E2\u53EF\u4EE5\u72EC\u7ACB\u6784\u5EFA\u7A0B\u5E8F\uFF0C\u4E5F\u652F\u6301\u5404\u79CD\u6846\u67B6\uFF0C\u800C\u4E14\u5927\u5927\u964D\u4F4E\u5404\u79CD\u6846\u67B6\u4F7F\u7528\u96BE\u5EA6\uFF1B</p></li><li><p>\u652F\u6301\u4E8B\u52A1\u7BA1\u7406\uFF0C\u65B9\u4FBF\u8FDB\u884C\u4E8B\u7269\u64CD\u4F5C\uFF1B</p></li><li><p>\u964D\u4F4E\u4E86\u5404\u79CD API \u7684\u5F00\u53D1\u96BE\u5EA6\uFF1B</p></li></ul><h3 id="spring-\u7684\u7EC4\u6210" tabindex="-1"><a class="header-anchor" href="#spring-\u7684\u7EC4\u6210" aria-hidden="true">#</a> Spring \u7684\u7EC4\u6210</h3><p><img src="https://s1.ax1x.com/2020/07/16/UD3qht.png" alt="img" loading="lazy"></p><p>Spring \u662F\u4E00\u4E2A\u5206\u5C42\u67B6\u6784\uFF0C\u4E3B\u8981\u7531\u5982\u4E0B 7 \u5927\u6A21\u5757\u6240\u6784\u6210\u3002Spring \u6A21\u5757\u4F4D\u4E8E\u6838\u5FC3\u5BB9\u5668\uFF0C\u5B9A\u4E49\u4E86\u521B\u5EFA\u3001\u914D\u7F6E\u548C\u7BA1\u7406 Bean \u7684\u65B9\u5F0F\u3002</p><ol><li><p><strong>Spring Core</strong>\uFF1A\u63D0\u4F9B Spring \u6846\u67B6\u57FA\u672C\u529F\u80FD\uFF0C\u4E3B\u8981\u7EC4\u4EF6\u662F BeanFactory\uFF0C\u662F\u5DE5\u5382\u6A21\u5F0F\u7684\u5B9E\u73B0\uFF0C\u901A\u8FC7 IOC \u673A\u5236\u5C06\u5E94\u7528\u7A0B\u5E8F\u7684\u914D\u7F6E\u548C\u4F9D\u8D56\u6027\u89C4\u8303\u4E0E\u5B9E\u9645\u7684\u5E94\u7528\u7A0B\u5E8F\u4EE3\u7801\u5206\u5F00\u3002</p></li><li><p><strong>Spring Context</strong>\uFF1A\u4E00\u4E2A\u914D\u7F6E\u6587\u4EF6\uFF0C\u7ED9 Spring \u6846\u67B6\u63D0\u4F9B\u4E0A\u4E0B\u6587\u4FE1\u606F\uFF0C\u4E0A\u4E0B\u6587\u5305\u62EC JNDI\u3001EJB\u3001\u7535\u5B50\u90AE\u4EF6\u3001\u56FD\u9645\u5316\u3001\u6821\u9A8C\u548C\u8C03\u5EA6\u7B49\u4F01\u4E1A\u670D\u52A1\u3002</p></li><li><p><strong>Spring AOP</strong> \uFF1A\u901A\u8FC7\u914D\u7F6E\u7BA1\u7406\u7279\u6027\uFF0CSpring AOP \u76F4\u63A5\u5C06 AOP\uFF08\u9762\u5411\u5207\u9762\uFF09\u529F\u80FD\u96C6\u6210\u5230 Spring \u6846\u67B6\u3002\u4ECE\u800C\u6211\u4EEC\u80FD\u591F\u5341\u5206\u65B9\u4FBF\u7684\u4F7F\u7528 Spring \u6846\u67B6\u6765\u7BA1\u7406\u4EFB\u4F55\u652F\u6301 AOP \u7684\u5BF9\u8C61\u3002\u6A21\u5757\u4E3A\u57FA\u4E8E Spring \u7684\u5E94\u7528\u7A0B\u5E8F\u4E2D\u7684\u5BF9\u8C61\u63D0\u4F9B\u4E86\u4E8B\u52A1\u7BA1\u7406\u670D\u52A1\u3002\u901A\u8FC7\u4F7F\u7528\u8BE5\u7EC4\u4EF6\uFF0C\u53EF\u4EE5\u4E0D\u4F9D\u8D56\u5176\u4ED6\u7EC4\u4EF6\u4E5D\u6C5F\u58F0\u660E\u6027\u4E8B\u52A1\u7BA1\u7406\u96C6\u6210\u5230\u5E94\u7528\u7A0B\u5E8F\u4E2D\u3002</p></li><li><p><strong>Spring DAO</strong>\uFF1AJDBC DAO \u62BD\u8C61\u5C42\u63D0\u4F9B\u4E86\u6709\u610F\u4E49\u7684\u5F02\u5E38\u5C42\u6B21\u7ED3\u6784\uFF0C\u53EF\u4EE5\u7528\u6765\u7BA1\u7406\u5F02\u5E38\u5904\u7406\u548C\u4E0D\u540C\u6570\u636E\u5E93\u4F9B\u5E94\u5546\u629B\u51FA\u7684\u9519\u8BEF\u4FE1\u606F\u3002\u5F02\u5E38\u5C42\u6B21\u7ED3\u6784\u7B80\u5316\u4E86\u9519\u8BEF\u5904\u7406\uFF0C\u800C\u4E14\u6781\u5927\u964D\u4F4E\u4E86\u9700\u8981\u7F16\u5199\u7684\u5F02\u5E38\u4EE3\u7801\u6570\u91CF\u3002Spring DAO \u9762\u5411 JDBC \u7684\u5F02\u5E38\u9075\u4ECE\u901A\u7528\u7684 DAO \u5F02\u5E38\u5C42\u6B21\u7ED3\u6784\u3002</p></li><li><p><strong>Spring ORM</strong>\uFF1ASpring \u6846\u67B6\u4E2D\u63D2\u5165\u4E86\u82E5\u5E72\u4E2A ORM \u6846\u67B6\uFF0C\u4ECE\u800C\u63D0\u4F9B\u4E86 ORM \u7684\u5BF9\u8C61\u5173\u7CFB\u5DE5\u5177\uFF0C\u5176\u4E2D\u5305\u62EC JDO\u3001Hibernate \u548C iBatis SQL Map\uFF0C\u8FD9\u4E9B\u90FD\u9075\u4ECE Spring \u7684\u901A\u7528\u4E8B\u52A1\u548C DAO \u5F02\u5E38\u5C42\u6B21\u7ED3\u6784\uFF1B</p></li><li><p><strong>Spring Web</strong>\uFF1AWeb \u4E0A\u4E0B\u6587\u6A21\u5757\u5EFA\u7ACB\u5728\u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u6A21\u5757\u4E4B\u4E0A\uFF0C\u4E3A\u57FA\u4E8E Web \u7684\u5E94\u7528\u7A0B\u5E8F\u63D0\u4F9B\u4E86\u4E0A\u4E0B\u6587\uFF0C\u6240\u4EE5 Spring \u6846\u67B6\u652F\u6301\u4E0E Jakarta Structs \u7684\u96C6\u6210\u3002\u540C\u65F6\u8BE5\u6A21\u5757\u8FD8\u7B80\u5316\u4E86\u5904\u7406\u591A\u90E8\u5206\u8BF7\u6C42\u4EE5\u53CA\u8BF7\u6C42\u53C2\u6570\u7ED1\u5B9A\u5230\u57DF\u5BF9\u8C61\u7684\u5DE5\u4F5C\u3002</p></li><li><p><strong>Spring Web MVC</strong>\uFF1AMVC \u662F\u4E00\u4E2A\u5168\u529F\u80FD\u7684\u6784\u5EFA Web \u5E94\u7528\u7684 MVC \u5B9E\u73B0\uFF0C\u53EF\u4EE5\u901A\u8FC7\u7B56\u7565\u63A5\u53E3\u5BF9 MVC \u6846\u67B6\u5B9E\u73B0\u9AD8\u5EA6\u53EF\u914D\u7F6E\u3002\u800C\u4E14 MVC \u8FD8\u5BB9\u7EB3\u4E86 JSP\u3001Velocity\u3001Tiles \u7B49\u89C6\u56FE\u6280\u672F\u3002</p></li></ol><p><img src="https://s1.ax1x.com/2020/07/16/UDJdpt.png" alt="img" loading="lazy"></p><h3 id="xml-\u914D\u7F6E-vs-java-\u914D\u7F6E" tabindex="-1"><a class="header-anchor" href="#xml-\u914D\u7F6E-vs-java-\u914D\u7F6E" aria-hidden="true">#</a> XML \u914D\u7F6E VS Java \u914D\u7F6E</h3><p>\u5BF9\u4E8E\u4E4B\u524D\u7684\u7248\u672C\uFF0CSpring \u5BB9\u5668\u5C06\u5404\u4E2A\u7EC4\u4EF6\u8FDE\u63A5\u8D77\u6765\u7684\u65B9\u5F0F\u662F\u901A\u8FC7 XML \u914D\u7F6E\uFF0C\u4F46\u73B0\u5728\u7684\u7248\u672C\u4E2D\u66F4\u591A\u7684\u662F\u4F7F\u7528\u57FA\u4E8E Java \u7684\u914D\u7F6E\uFF0C\u5982\u4E0B\u9762\u57FA\u4E8E XML \u7684\u914D\u7F6E\u7B49\u6548\u4E8E\u57FA\u4E8E Java \u7684\u914D\u7F6E\u3002</p><ul><li>\u57FA\u4E8E XML \u914D\u7F6E</li></ul><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>bean</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>productService<span class="token punctuation">&quot;</span></span> <span class="token attr-name">calss</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>com.cunyu.ProductService<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>bean</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>bean</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>consumerService<span class="token punctuation">&quot;</span></span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>com.cunyu.ConsumerService<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
	<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>constructor-arg</span> <span class="token attr-name">ref</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>productService<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>bean</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>\u57FA\u4E8E Java \u914D\u7F6E</li></ul><div class="language-java ext-java line-numbers-mode"><pre class="language-java"><code><span class="token annotation punctuation">@Configuration</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ServiceConfig</span><span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Bean</span>
    <span class="token keyword">public</span> <span class="token class-name">ProductService</span> <span class="token function">productService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">ProductService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token annotation punctuation">@Bean</span>
    <span class="token keyword">public</span> <span class="token class-name">ConsumerService</span> <span class="token function">consumerService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">ConsumerService</span><span class="token punctuation">(</span><span class="token function">productService</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>\u5728\u57FA\u4E8E Java \u7684\u914D\u7F6E\u4E2D\uFF0C<code>@Configuration</code> \u5411 Spring \u8868\u660E\u8BE5\u7C7B\u662F\u4E00\u4E2A\u914D\u7F6E\u7C7B\uFF0C\u4E3A Spring \u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u63D0\u4F9B Bean\u3002\u800C <code>@Bean</code> \u6CE8\u89E3\u5219\u6307\u793A\u7C7B\u65B9\u6CD5\u8FD4\u56DE\u7684\u5BF9\u8C61\u5E94\u4F5C\u4E3A Beans \u6DFB\u52A0\u5230\u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u4E2D\u3002</p><p>\u90A3\u4F60\u53EF\u80FD\u60F3\uFF0C\u65E2\u7136\u4E4B\u524D\u6709\u4E86 XML \u914D\u7F6E\u7684\u65B9\u5F0F\uFF0C\u90A3\u4E48\u4E3A\u4EC0\u4E48\u540E\u6765\u7684\u7248\u672C\u4E2D\u53C8\u52A0\u5165\u4E86\u57FA\u4E8E Java \u7684\u914D\u7F6E\u65B9\u5F0F\u5462\uFF1F\u57FA\u4E8E Java \u7684\u914D\u7F6E\u65B9\u5F0F\u76F8\u6BD4\u4E8E XML \u7684\u914D\u7F6E\u65B9\u5F0F\uFF0C<strong>\u5305\u542B\u4E86\u66F4\u9AD8\u7684\u7C7B\u578B\u5B89\u5168\u6027\u548C\u66F4\u9AD8\u7684\u53EF\u91CD\u6784\u6027</strong>\u3002\u800C\u4E14\u4EC5\u5F53 Spring \u65E0\u6CD5\u81EA\u52A8\u914D\u7F6E\u7EC4\u4EF6\u65F6\uFF0C\u624D\u9700\u8981\u901A\u8FC7 <strong>XML\u7684\u914D\u7F6E\u65B9\u5F0F</strong> \u6216\u8005 <strong>\u57FA\u4E8E Java \u7684\u914D\u7F6E\u65B9\u5F0F</strong> \u6765\u8FDB\u884C\u663E\u5F0F\u914D\u7F6E\u3002</p><p><strong>\u81EA\u52A8\u914D\u7F6E</strong> \u5373 <strong>\u81EA\u52A8\u88C5\u914D + \u7EC4\u4EF6\u626B\u63CF</strong>\u3002\u6709\u8D56\u4E8E <strong>\u7EC4\u4EF6\u626B\u63CF</strong>\uFF0CSpring \u80FD <strong>\u81EA\u52A8\u4ECE\u5E94\u7528\u7A0B\u5E8F\u7684\u7C7B\u8DEF\u5F84\u4E2D\u53D1\u73B0\u7EC4\u4EF6\uFF0C\u540C\u65F6\u5C06\u5176\u521B\u5EFA\u4E3A Spring \u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u4E2D\u7684 Bean</strong>\u3002\u800C\u901A\u8FC7 <strong>\u81EA\u52A8\u88C5\u914D\uFF0CSpring \u5C06\u81EA\u52A8\u5C06\u7EC4\u4EF6\u4E0E\u5176\u6240\u4F9D\u8D56\u7684\u5176\u4ED6 Bean \u4E00\u8D77\u6CE8\u5165</strong>\u3002</p><p>\u6700\u8FD1\u968F\u7740 Spring Boot \u7684\u63A8\u51FA\uFF0C\u81EA\u52A8\u914D\u7F6E\u7684\u4F18\u52BF\u8FDB\u4E00\u6B65\u52A0\u5F3A\uFF0C\u5728\u8FD9\u79CD\u914D\u7F6E\u4E2D\uFF0CSpring Boot \u5C06\u6839\u636E <strong>\u7C7B\u8DEF\u5F84\u4E2D\u7684\u6761\u76EE\u3001\u73AF\u5883\u53D8\u91CF\u548C\u5176\u4ED6\u56E0\u7D20\uFF0C\u5408\u7406\u731C\u6D4B\u6240\u9700\u914D\u7F6E\u7684\u7EC4\u4EF6\uFF0C\u5C06\u5176\u8FDE\u63A5\u5728\u4E00\u8D77</strong>\u3002Spring Boot \u4E2D\u7684\u81EA\u52A8\u914D\u7F6E\u5927\u5927\u51CF\u5C11\u4E86\u6784\u5EFA\u5E94\u7528\u7A0B\u5E8F\u6240\u9700\u7684\u663E\u5F0F\u914D\u7F6E\u7684\u6570\u91CF\uFF0C\u589E\u5F3A\u4E86 Spring \u5F00\u53D1\u7684\u80FD\u529B\u3002</p><h2 id="\u521D\u59CB\u5316-spring-\u5E94\u7528\u7A0B\u5E8F" tabindex="-1"><a class="header-anchor" href="#\u521D\u59CB\u5316-spring-\u5E94\u7528\u7A0B\u5E8F" aria-hidden="true">#</a> \u521D\u59CB\u5316 Spring \u5E94\u7528\u7A0B\u5E8F</h2><h3 id="\u9879\u76EE\u7ED3\u6784" tabindex="-1"><a class="header-anchor" href="#\u9879\u76EE\u7ED3\u6784" aria-hidden="true">#</a> \u9879\u76EE\u7ED3\u6784</h3><p>\u5BF9\u4E8E\u4E00\u4E2A Spring \u9879\u76EE\u800C\u8A00\uFF0C\u5176\u7ED3\u6784\u4E3B\u8981\u5305\u62EC\u4EE5\u4E0B\u90E8\u5206\uFF1A</p><ol><li><code>src/main/java</code>\uFF1A\u8BE5\u76EE\u5F55\u4E3B\u8981\u5305\u542B\u5E94\u7528\u7A0B\u5E8F\u7684\u6E90\u7801\uFF0C\u4E3B\u8981\u53EF\u5206\u4E3A\u5982\u4E0B\u51E0\u7C7B\uFF1A</li></ol><ul><li><ul><li><code>build</code> \uFF1A\u5DE5\u7A0B\u542F\u52A8\u7C7B\uFF1B</li><li><code>entity</code> \uFF1A\u5B9E\u4F53\u7C7B\uFF1B</li></ul></li><li><ul><li><code>mapper</code> \uFF1A\u6570\u636E\u8BBF\u95EE\u5C42\uFF1B</li><li><code>service</code> \uFF1A\u6570\u636E\u670D\u52A1\u5C42\uFF0C\u4E1A\u52A1\u7C7B\u4EE3\u7801\uFF1B</li></ul></li><li><ul><li><code>controller</code> \uFF1A\u524D\u7AEF\u8BBF\u95EE\u63A7\u5236\u5668\uFF1B</li><li><code>config</code> \uFF1A\u914D\u7F6E\u4FE1\u606F\u7C7B\uFF1B</li></ul></li><li><ul><li><code>dto</code>\uFF1A\u6570\u636E\u4F20\u8F93\u5C42\uFF1B</li><li><code>utils</code> \uFF1A\u5DE5\u5177\u7C7B\uFF1B</li></ul></li><li><ul><li><code>constant</code> \uFF1A\u5E38\u7528\u63A5\u53E3\u7C7B\uFF1B</li><li><code>vo</code> \uFF1A\u6570\u636E\u4F20\u8F93\u7C7B\uFF1B</li></ul></li><li><ul><li><code>Application.java</code>\uFF1A\u9879\u76EE\u7684\u542F\u52A8\u7C7B\uFF1B</li></ul></li></ul><ol><li><p><code>src/main/resources</code>\uFF1A\u76F8\u5173\u8D44\u6E90\u6587\u4EF6\uFF1B</p></li><li><p><code>src/test/java</code>\uFF1A\u6D4B\u8BD5\u76F8\u5173\u4EE3\u7801\uFF1B</p></li><li><p><code>src/test/resources</code>\uFF1A\u6D4B\u8BD5\u76F8\u5173\u8D44\u6E90\uFF1B</p></li><li><p><code>pom.xml</code>\uFF1AMaven \u6784\u5EFA\u89C4\u8303\uFF0C\u5305\u542B\u4E00\u4E9B\u9879\u76EE\u53CA\u4F9D\u8D56\u65B9\u9762\u7684\u914D\u7F6E\u3002</p></li></ol><h3 id="\u9879\u76EE\u542F\u52A8\u7C7B" tabindex="-1"><a class="header-anchor" href="#\u9879\u76EE\u542F\u52A8\u7C7B" aria-hidden="true">#</a> \u9879\u76EE\u542F\u52A8\u7C7B</h3><p>\u9879\u76EE\u542F\u52A8\u7C7B\uFF0C\u5373\u8FD0\u884C jar \u6587\u4EF6\u65F6\u7528\u6765\u5F15\u5BFC\u5E94\u7528\u7A0B\u5E8F\u6267\u884C\u7684\u7C7B\uFF0C\u4E5F\u5C31\u662F\u9879\u76EE\u7ED3\u6784\u4E2D\u7684 <code>Application.java</code>\uFF0C\u4E0B\u9762\u662F\u4E00\u4E2A\u9879\u76EE\u542F\u52A8\u7C7B\u7684\u5B9E\u4F8B\uFF1A</p><div class="language-java ext-java line-numbers-mode"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>boot<span class="token punctuation">.</span></span><span class="token class-name">SpringApplication</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>boot<span class="token punctuation">.</span>autoconfigure<span class="token punctuation">.</span></span><span class="token class-name">SpringBootApplication</span><span class="token punctuation">;</span>

<span class="token annotation punctuation">@SpringBootApplication</span>
<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">TacoCloudApplication</span> <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token class-name">SpringApplication</span><span class="token punctuation">.</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token class-name">TacoCloudApplication</span><span class="token punctuation">.</span><span class="token keyword">class</span><span class="token punctuation">,</span> args<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>\u5176\u4E2D <code>@SpringBootApplication</code> \u6CE8\u89E3\u8BF4\u660E\u8BE5\u7C7B\u662F\u4E00\u4E2A Spring \u5F15\u5BFC\u5E94\u7528\u7A0B\u5E8F\uFF0C\u4F46\u5B9E\u9645\u4E0A\u5B83\u662F\u7EC4\u5408\u4E86\u4E0B\u5217\u4E09\u4E2A\u6CE8\u89E3\u7684\u590D\u5408\u5E94\u7528\u6CE8\u89E3\uFF1A</p><ul><li><p><code>@SpringBootConfiguration</code>\uFF1A<strong>\u6307\u5B9A\u8BE5\u7C7B\u4E3A\u914D\u7F6E\u7C7B</strong>\u3002</p></li><li><p><code>@EnableAutoConfiguration</code>\uFF1A<strong>\u542F\u7528 Spring \u81EA\u52A8\u914D\u7F6E</strong>\u3002</p></li><li><p><code>@ComponentScan</code>\uFF1A<strong>\u542F\u7528\u7EC4\u4EF6\u626B\u63CF</strong>\u3002\u5141\u8BB8\u58F0\u660E\u5176\u4ED6\u5E26\u6709 <code>@Component</code>\u3001<code>@Controller</code>\u3001<code>@Service</code> \u7B49\u6CE8\u89E3\u7684\u7C7B\uFF0C\u4EE5\u4FBF\u8BA9Spring \u81EA\u52A8\u53D1\u73B0\u4ED6\u4EEC\u5E76\u5C06\u4ED6\u4EEC\u6CE8\u518C\u4E3A Spring \u5E94\u7528\u7A0B\u5E8F\u4E0A\u4E0B\u6587\u4E2D\u7684\u7EC4\u4EF6\u3002</p></li></ul><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>OK\uFF0C\u603B\u7ED3\u4E00\u4E0B\u4ECA\u5929\u7684\u5185\u5BB9\uFF0C\u4E3B\u8981\u8BB2\u4E86\uFF1A</p><ol><li><p>Spring \u5BB6\u65CF\u6210\u5458\u7684\u5185\u5BB9\uFF1B</p></li><li><p>Spring \u7684\u6982\u5FF5</p></li><li><p>Spring \u7684\u7279\u70B9</p></li><li><p>Spring \u7684\u7EC4\u6210</p></li><li><p>\u914D\u7F6E Spring \u7684\u4E24\u79CD\u65B9\u5F0F</p></li><li><p>\u4E00\u4E2A Spring \u9879\u76EE\u5E38\u89C1\u7684\u9879\u76EE\u7ED3\u6784</p></li></ol><p>\u597D\u4E86\uFF0C\u4EE5\u4E0A\u5C31\u662F\u4ECA\u5929\u7684\u6240\u6709\u5185\u5BB9\u4E86\u3002\u539F\u521B\u4E0D\u6613\uFF0C\u5982\u679C\u4F60\u89C9\u5F97\u6211\u7684\u5185\u5BB9\u5BF9\u4F60\u6709\u6240\u5E2E\u52A9\uFF0C\u90A3\u5C31\u5E2E\u5FD9\u70B9\u8D5E\u5173\u6CE8\u5427\uFF01</p>`,56);function t(e,o){return p}var c=a(s,[["render",t],["__file","spring-intro.html.vue"]]);export{c as default};
